create table dirkspzm32.pzm_prod_business_units_bereiche (
    bu_id                number(*, 0) not null enable,
    bu_name              varchar2(100 char) not null enable,
    bu_bemerkungen       varchar2(255 char),
    created_date         date default sysdate not null enable,
    created_login_id     number(*, 0) default - 1 not null enable,
    last_change_date     date,
    last_change_login_id number(*, 0)
);

alter table dirkspzm32.pzm_prod_business_units_bereiche
    add constraint pk_business_unit_id primary key ( bu_id )
        using index enable;


